  `user_deduct_fee_amount` bigint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'з”ЁжҲ·жүӢз»ӯиҙ№',
  `user_refund_amount` bigint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'з”ЁжҲ·е®һйҖҖйҮ‘йўқпјҢ= з”ЁжҲ·е®һд»ҳ + ж”Ҝд»ҳдјҳжғ  - з”ЁжҲ·жүӢз»ӯиҙ№',
  `refund_type` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'йҖҖж¬ҫзұ»еһӢ',
  `order_type` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'и®ўеҚ•зұ»еһӢ',
  `trade_type` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'дәӨжҳ“зұ»еһӢ',
  `reject_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'жӢ’з»қеҺҹеӣ ',
  `reason` json NULL COMMENT 'з”іиҜ·еҺҹеӣ ',
  `data` json NULL COMMENT 'еҺҹе§Ӣж•°жҚ®',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `sync_at` timestamp NULL DEFAULT NULL COMMENT 'еҗҢжӯҘж—¶й—ҙ',
