  `member_id` bigint UNSIGNED NOT NULL COMMENT 'дјҡе‘ҳID',
  `tid` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'и®ўеҚ•еҸ·',
  `gid` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'и®ўеҚ•е•Ҷе“ҒиЎЁID',
  `afs_bn` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'з”іиҜ·е”®еҗҺзј–еҸ·',
  `refunds_type` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'йҖҖж¬ҫзұ»еһӢ,0-е”®еҗҺз”іиҜ·йҖҖж¬ҫ,1-еҸ–ж¶Ҳи®ўеҚ•йҖҖж¬ҫ,2-жӢ’ж”¶и®ўеҚ•йҖҖж¬ҫ,3-иҷҡжӢҹе•Ҷе“ҒиҝҮжңҹйҖҖж¬ҫ',
  `status` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'е®Ўж ёзҠ¶жҖҒ,0-жңӘе®Ўж ё,1-е·Іе®ҢжҲҗйҖҖж¬ҫ,2-е·Ій©іеӣһ,3-е•Ҷе®¶е®Ўж ёйҖҡиҝҮ,4-е•Ҷе®¶е®Ўж ёдёҚйҖҡиҝҮ,5-е•Ҷе®¶ејәеҲ¶е…іеҚ•,6-е№іеҸ°ејәеҲ¶е…іеҚ•,7-йҖҖж¬ҫдёӯ,8-йҖҖж¬ҫеӨұиҙҘ',
  `refunds_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'з”іиҜ·йҖҖж¬ҫеҺҹеӣ ',
  `order_price` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'и®ўеҚ•йҮ‘йўқ',
  `total_price` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'еә”йҖҖйҮ‘йўқ',
  `refund_fee` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'е®һйҖҖйҮ‘йўқ',
  `points_fee` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'з§ҜеҲҶжҠөжүЈйҮ‘йўқ',
  `coupon_fee` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'дјҳжғ ж”Ҝд»ҳйҮ‘йўқ',
  `use_coupon_id` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'дҪҝз”Ёдјҳжғ зҡ„йӣҶеҗҲ',
  `return_freight` tinyint UNSIGNED NOT NULL DEFAULT 1 COMMENT 'жҳҜеҗҰйҖҖиҝҗиҙ№,1-йҖҖиҝҗиҙ№,2-дёҚйҖҖиҝҗиҙ№',
  `consume_point_fee` bigint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'жҠөжүЈзҡ„з§ҜеҲҶ',
  `refund_point` bigint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'е®һйҖҖз§ҜеҲҶ',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `em_trade_refunds_refund_bn_unique`(`refund_bn` ASC) USING BTREE,
  INDEX `em_trade_refunds_member_id_index`(`member_id` ASC) USING BTREE,
  INDEX `em_trade_refunds_refunds_type_index`(`refunds_type` ASC) USING BTREE,
  INDEX `em_trade_refunds_afs_bn_index`(`afs_bn` ASC) USING BTREE,
  INDEX `em_trade_refunds_status_index`(`status` ASC) USING BTREE,
  INDEX `em_trade_refunds_tid_index`(`tid` ASC) USING BTREE,
  INDEX `em_trade_refunds_gid_index`(`gid` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 237320 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'йҖҖж¬ҫз”іиҜ·иЎЁ' ROW_FORMAT = Dynamic;

