  `discount_fee_shop` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'еә—й“әдҝғй”Җдјҳжғ йҮ‘йўқ',
  `obtain_points` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'д№°е®¶иҺ·еҫ—з§ҜеҲҶ',
  `receiver_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ж”¶иҙ§дәәе§“еҗҚ',
  `receiver_area` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ж”¶иҙ§дәәжүҖеңЁең°еҢә',
  `receiver_address` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ж”¶иҙ§дәәиҜҰз»Ҷең°еқҖ',
  `receiver_zip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'ж”¶иҙ§дәәйӮ®зј–',
  `receiver_tel` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'ж”¶иҙ§дәәз”өиҜқ',
