  `invoice_info` json NULL COMMENT 'еҸ‘зҘЁдҝЎжҒҜ',
  `shipping_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'иҝҗйҖҒж–№ејҸ',
