  `pick_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0' COMMENT 'иҮӘжҸҗз Ғ',
  `express_no` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'еҝ«йҖ’еҚ•еҸ·',
  `ip` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'IPең°еқҖ',
  `pay_time` datetime NULL DEFAULT NULL COMMENT 'д»ҳж¬ҫж—¶й—ҙ',
  `end_time` datetime NULL DEFAULT NULL COMMENT 'з»“жқҹж—¶й—ҙ,ж•ҙдёӘи®ўеҚ•ж”¶иҙ§orе”®еҗҺе®Ңз»“зҡ„ж—¶й—ҙ',
  `consign_time` datetime NULL DEFAULT NULL COMMENT 'еҚ–е®¶еҸ‘иҙ§ж—¶й—ҙ',
