  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'еҗҚз§°еӨҮжіЁ',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'дҪҝз”ЁиҜҙжҳҺ',
  `total_num` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'еҸ‘ж”ҫж•°йҮҸ',
  `stock_num` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'еү©дҪҷж•°йҮҸ',
