  `total_used` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'дҪҝз”Ёж•°йҮҸ',
  `status` tinyint UNSIGNED NOT NULL DEFAULT 1 COMMENT 'дјҳжғ еҲёзҠ¶жҖҒпјҡ1-еҸҜз”ЁпјҢ0-еӨұж•ҲпјҢ2-еҫ…е®Ўж ёпјҢ3-е®Ўж ёдёҚйҖҡиҝҮ',
  `type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'reward' COMMENT 'дјҳжғ еҲёзұ»еһӢreward:ж»ЎеҮҸдјҳжғ еҲё, discount:жҠҳжүЈдјҳжғ еҲёпјҢrules:еӨҡи§„еҲҷпјҢvoucher:д»ЈйҮ‘еҲёпјҢparking:еҒңиҪҰеҲёпјҢexchange:е…‘жҚўеҲё',
  `cover_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'е°ҒйқўеӣҫзүҮ',
  `suit_goods` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'йҖӮз”Ёе•Ҷе“Ғпјҡ0-е…ЁйғЁе•Ҷе“ҒеҸҜз”ЁпјҢ1-жҢҮе®ҡе•Ҷе“ҒеҸҜз”ЁпјҢ2-йғЁеҲҶе•Ҷе“ҒдёҚеҸҜз”Ё',
  `goods_ids` json NULL COMMENT 'жҢҮе®ҡзҡ„е•Ҷе“ҒID',
  `amount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'и®ўеҚ•ж»Ўи¶ійҮ‘йўқ: 0-ж— дҪҝз”Ёй—Ёж§ӣ',
  `discount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'дјҳжғ йҮ‘йўқ/жҠҳжүЈ',
  `max_discount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'жңҖеӨ§дјҳжғ йҮ‘йўқ',
  `date_type` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'з”ЁеҲёж—¶й—ҙж–№ејҸ:0-жңүж•ҲжңҹеҶ…,1-йўҶеҲёеҪ“ж—Ҙиө·,2-йўҶеҲёж¬Ўж—Ҙиө·',
  `start_time` timestamp NULL DEFAULT NULL COMMENT 'ејҖе§Ӣж—Ҙжңҹ',
  `end_time` timestamp NULL DEFAULT NULL COMMENT 'з»“жқҹж—Ҙжңҹ',
  `valid_period` decimal(8, 2) NULL DEFAULT NULL COMMENT 'жңүж•Ҳжңҹ(h)пјҲз”ЁеҲёж—¶й—ҙж–№ејҸдёә1гҖҒ2ж—¶пјҢеҝ…еЎ«пјү',
  `days` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'йўҶеҲёеҗҺеҮ еӨ©еҸҜз”Ё',
  `able_take_num` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'жҜҸдәәйҷҗйўҶж¬Ўж•°:0-ж— йҷҗеҲ¶',
  `day_take_num` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'жҜҸдәәжҜҸж—ҘйҷҗйўҶж¬Ўж•°:0-ж— йҷҗеҲ¶',
  `class_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'еҲҶзұ»ID',
  `project_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT 'йЎ№зӣ®ID',
  `publish_channel` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'platform' COMMENT 'еҸ‘иЎҢжё йҒ“пјҢplatform-е№іеҸ°пјҢshop-е•Ҷе®¶',
  `scene` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'online' COMMENT 'еңәжҷҜпјҢonline-зәҝдёҠпјҢoffline-зәҝдёӢ',
  `receive_start` datetime NULL DEFAULT NULL COMMENT 'еҸҜйўҶеҸ–ејҖе§Ӣж—¶й—ҙ',
  `receive_end` datetime NULL DEFAULT NULL COMMENT 'еҸҜйўҶеҸ–з»“жқҹж—¶й—ҙ',
  `reject_reason` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'й©іеӣһеҺҹеӣ ',
  `expand` json NULL COMMENT 'жӢ“еұ•еӯ—ж®өз”ЁдәҺеӯҳеӮЁе…¶е®ғйңҖжұӮеӯ—ж®ө',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `hidden` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT 'жҳҜеҗҰеңЁдјҳжғ еҲёеҲ—иЎЁдёӯжҳҫзӨә 1дёҚжҳҫзӨә 0жҳҫзӨә',
  `distribute_channel` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'online' COMMENT 'еҸ‘ж”ҫжё йҒ“пјҢonline-зәҝдёҠпјҢactivity-жҙ»еҠЁпјҢpush-жүӢеҠЁжҺЁйҖҒ',
  `sale_price` double(10, 2) NOT NULL DEFAULT 0.00 COMMENT 'й”Җе”®д»·ж ј',
  `sale_state` smallint NOT NULL DEFAULT 0 COMMENT 'й”Җе”®зҠ¶жҖҒ,0-дёӢжһ¶,1-жӯЈеёё',
  `coin_num` int UNSIGNED NULL DEFAULT NULL COMMENT 'е”®еёҒжңәж•°йҮҸ',
  `remarks` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'й©іеӣһеҺҹеӣ ',
  `collect_type` tinyint UNSIGNED NOT NULL DEFAULT 1 COMMENT 'йҷҗеҲ¶йўҶеҸ–зұ»еһӢ 1 ж—Ҙ 2 жңҲ 3е№ҙ',
  `valid_type` tinyint UNSIGNED NOT NULL DEFAULT 1 COMMENT 'жңүж•Ҳжңҹзұ»еһӢ  1 ж—Ҙ 2 жңҲ 3е№ҙ',
  `grade_id` json NULL COMMENT 'зӯүзә§йҷҗеҲ¶',
  `wx_qr_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'е°ҸзЁӢеәҸдәҢз»ҙз Ғи·Ҝеҫ„',
  `is_transfer` tinyint NULL DEFAULT 0 COMMENT 'иҪ¬иө   1 ејҖеҗҜиҪ¬иө   0 е…ій—ӯиҪ¬иө ',
  `img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'еӣҫзүҮ',
  `send_shops` json NULL COMMENT 'жҙҫеҲёе•Ҷе®¶',
  `is_superpose` tinyint NULL DEFAULT 0 COMMENT 'жҳҜеҗҰиғҪеҸ еҠ дҪҝз”Ёпјҡ1-жҳҜпјҢ0-еҗҰ',
  `max_superpose_num` int UNSIGNED NULL DEFAULT 1 COMMENT 'жңҖеӨҡеҸҜеҸ еҠ ж•°йҮҸ',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `em_ump_coupons_shop_id_index`(`shop_id` ASC) USING BTREE,
  INDEX `em_ump_coupons_type_index`(`type` ASC) USING BTREE,
  INDEX `em_ump_coupons_suit_goods_index`(`suit_goods` ASC) USING BTREE,
  INDEX `em_ump_coupons_date_type_index`(`date_type` ASC) USING BTREE,
  INDEX `em_ump_coupons_class_id_index`(`class_id` ASC) USING BTREE,
  INDEX `em_ump_coupons_project_id_index`(`project_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10034 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'дјҳжғ еҲёиЎЁ' ROW_FORMAT = Dynamic;

