INSERT INTO `em_rule_explains` VALUES (1, 1, 'еҒңиҪҰзјҙиҙ№', 0, 1, 'parking', '<p>еҒңиҪҰзјҙиҙ№йЎ»зҹҘ</p><p>1.еҮӯи¶Ҡз§ҖзҒҜдјҡжёёзҺ©зҘЁеңЁзҺ°еңәйўҶеҸ–1е°Ҹж—¶еҒңиҪҰзҘЁзјҙиҙ№дё“еҢәпјҢжң¬еҲёдёәйҷҗйҮҸеҲёпјҢд»…йҖӮз”ЁдәҺжҷҹжҪ®дёӯеҝғе°ҸзЁӢеәҸ;</p><p>2.йўҶеҸ–1е°Ҹж—¶еҒңиҪҰеҲёзҡ„дјҡе‘ҳеҸҜжүӢеҠЁйҖүжӢ©еҒңиҪҰеҲёиҝӣиЎҢжҠөжүЈпјҢеҒңиҪҰдјҳжғ еҲёж— жі•дёҺз§ҜеҲҶжҠөжүЈеҒңиҪҰдјҳжғ еҸ еҠ дҪҝз”ЁпјҢиҜ·дјҡе‘ҳжҸҗеүҚзЎ®и®ӨеҒңиҪҰж—¶й—ҙжҲ–иҪҰиҫҶзҰ»еңәеүҚеҶҚиҝӣиЎҢеҒңиҪҰдјҳжғ еҲёе…‘жҚўпјҢ1еӨ©е°ҒйЎ¶3е°Ҹж—¶пјӣ</p><p>2.иҝһз»ӯеҒңж”ҫи¶…иҝҮ15еҲҶй’ҹзҡ„иҪҰиҫҶпјҢе…¶и®Ўиҙ№ж—¶й—ҙж®өдёҚи¶і15еҲҶй’ҹзҡ„йғЁеҲҶжҢү15еҲҶй’ҹи®Ўз®—;</p><p>3.8:00-22:00ж—¶ж®өе°ҸиҪҰж”¶иҙ№ж ҮеҮҶ:4е…ғ/15еҲҶй’ҹгҖҒ16е…ғ=1е°Ҹж—¶;</p><p>4.22:00-ж¬Ўж—Ҙ8:00ж—¶ж®өе°ҸиҪҰж”¶иҙ№ж ҮеҮҶ:5е…ғ=1е°Ҹж—¶гҖҒжңҖй«ҳйҷҗд»·10е…ғ;</p><p>5.24е°Ҹж—¶еҶ…дёҙж—¶еҒңиҪҰйҷҗйўқжңҖй«ҳйҷҗд»·128/еӨ©</p><p>6.ж”¶иҙ№ж ҮеҮҶд»ҘиҪҰеңәжңҖж–°йҖҡзҹҘе…¬зӨәдёәеҮҶ;</p><p>7.е…¬еҸёжңүжқғеңЁжі•еҫӢе…Ғи®ёзҡ„иҢғеӣҙеҶ…дҝқз•ҷеҜ№жң¬еҒңиҪҰдјҳжғ зҰҸеҲ©зҡ„жңҖз»Ҳи§ЈйҮҠжқғпјӣ</p><p>8.е…ідәҺеҒңиҪҰзјҙиҙ№й—®йўҳпјҢиҜ·иҒ”зі»дјҡе‘ҳе°ҸзЁӢеәҸеңЁзәҝе®ўжңҚжҲ–иҮҙз”өе®ўжңҚеүҚеҸ°020-26082202гҖӮ</p><p><br></p><p>жё©йҰЁжҸҗзӨәпјҡ</p><p>жң¬еҒңиҪҰеңәж”¶иҙ№дёҚжүҝжӢ…иҪҰиҫҶеҸҠиҪҰеҶ…иҙўзү©дҝқз®ЎпјҢиҜ·жіЁж„Ҹдҝқз®ЎеҘҪжӮЁзҡ„иҙөйҮҚзү©е“ҒпјҢзҰ»ејҖеүҚиҜ·е…ій—ӯиҪҰй—Ёе’ҢиҪҰзӘ—пјҢи°ЁйҳІиў«зӣ—гҖӮ</p>', '2025-11-05 16:06:06', '2025-11-05 16:06:06');
INSERT INTO `em_rule_explains` VALUES (2, 1, 'з§ҜеҲҶиҜҙжҳҺ', 0, 1, 'integralGuide', '<p><span style=\"color: rgb(0, 0, 0);\">1е…ғ=1з§ҜеҲҶпјҡиЈ…жңҚйҘ°гҖҒйһӢеҢ…гҖҒеҢ–еҰҶе“ҒгҖҒд№Ұеә—гҖҒйӣ¶е”®гҖҒе…¶д»–й…ҚеҘ—йӣ¶е”®гҖҒе„ҝз«Ҙз”Ёе“Ғпјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">5е…ғ=1з§ҜеҲҶпјҡеҢ…иЈ…йЈҹе“ҒгҖҒй…’жҘјгҖҒйӨҗйҘ®гҖҒзҫҺйЈҹе№ҝеңәгҖҒеҪұйҷўгҖҒе®¶е…·йӣ¶е”®пјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">50е…ғ=1з§ҜеҲҶпјҡж•°з Ғе®¶з”өгҖҒзҸ е®қй’ҹиЎЁгҖҒдҫҝеҲ©еә—гҖҒеҶ°еңәгҖҒдҪ“йӘҢдёҡжҖҒгҖҒеЁұд№җдёҡжҖҒгҖҒе®¶еұ…еӨ§еҚ–еңәпјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">100е…ғ=1з§ҜеҲҶпјҡй…ҚеҘ—и®ҫж–ҪгҖҒзҫҺе®№зҫҺдҪ“дҝқеҒҘгҖҒжҲҗдәәеҹ№и®ӯгҖҒе„ҝз«Ҙж•ҷиӮІпјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">1.зҷҫиҙ§гҖҒи¶…еёӮгҖҒеұ•еҺ…гҖҒеҠһе…¬е®ӨгҖҒе®¶иЈ…жңҚеҠЎдёҡжҖҒпјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">2.йӨҗйҘ®зұ»е•ҶжҲ·зҡ„еӨ§еһӢе®ҙеёӯж¶Ҳиҙ№пјҲеҰӮе©ҡе®ҙгҖҒе№ҙдјҡзӯүпјүпјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">3.иҙӯд№°е•ҶжҲ·зҡ„з§ҜеҲҶеҚЎгҖҒиҙӯзү©еҚЎгҖҒеӮЁеҖјеҚЎгҖҒд»ЈйҮ‘еҲёпјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">4.д»Ҙе…¬еҜ№з§Ғй“¶иЎҢиҪ¬иҙҰгҖҒз§ҒеҜ№з§Ғй“¶иЎҢиҪ¬иҙҰгҖҒз§Ғдәәеҫ®дҝЎжҲ–з§Ғдәәж”Ҝд»ҳе®қиҪ¬иҙҰеҮӯиҜҒгҖҒзҺ°йҮ‘ж”Ҝд»ҳж–№ејҸе®ҢжҲҗзҡ„ж¶Ҳиҙ№пјӣ</span></p><p><span style=\"color: rgb(0, 0, 0);\">5.йҖҡиҝҮз¬¬дёүж–№зәҝдёҠе№іеҸ°пјҲеҰӮеӨ§дј—зӮ№иҜ„гҖҒе…¶д»–еӨ–еҚ–е№іеҸ°зӯүпјүи®ўеҚ•гҖӮ</span></p>', '2025-11-05 16:26:59', '2025-11-05 16:26:59');
INSERT INTO `em_rule_explains` VALUES (3, 1, 'йҡҗз§ҒеҚҸи®®', 0, 1, 'member_shop', '<h2 class=\"ql-align-center\"><strong>йҡҗз§Ғж”ҝзӯ–</strong></h2><p>жң¬ж”ҝзӯ–йҖӮз”ЁдәҺжҷҹжҪ®C-WAVEжҸҗдҫӣзҡ„еҗ„йЎ№дјҡе‘ҳдә§е“ҒеҸҠжңҚеҠЎпјҢеҢ…жӢ¬зәҝдёҠгҖҒзәҝдёӢжүҖжҸҗдҫӣзҡ„иҙӯзү©дҪ“йӘҢеҸҠдёҺе…¶зӣёе…ізҡ„йЎҫе®ўжңҚеҠЎгҖҒжҷҹжҪ®C-WAVEдјҡе‘ҳжңҚеҠЎгҖҒдә§е“Ғзӣ®еҪ•еҶҢеҸҠе®Јдј иө„ж–ҷжҠ•йҖ’зӯүжңҚеҠЎгҖӮеҰӮжһңжӮЁжңүд»»дҪ•з–‘й—®гҖҒж„Ҹи§ҒжҲ–е»әи®®пјҢиҜ·йҖҡиҝҮд»ҘдёӢж–№ејҸдёҺжҷҹжҪ®C-WAVEиҒ”зі»пјҡ</p><p>з”өиҜқпјҡпјҲеҗҺз»ӯе•Ҷеңәе®ўжңҚеҸ°з”өиҜқпјү</p><p>жҷҹжҪ®C-WAVEпјҲд»ҘдёӢз®Җз§° вҖңжҲ‘д»¬вҖқпјүж·ұзҹҘдёӘдәәдҝЎжҒҜеҜ№жӮЁзҡ„йҮҚиҰҒжҖ§пјҢе№¶дјҡе°Ҫе…ЁеҠӣдҝқжҠӨжӮЁзҡ„дёӘдәәдҝЎжҒҜе®үе…ЁеҸҜйқ гҖӮжҲ‘д»¬иҮҙеҠӣдәҺз»ҙжҠӨжӮЁеҜ№жҲ‘д»¬зҡ„дҝЎд»»пјҢдҝқжҠӨжӮЁзҡ„дёӘдәәдҝЎжҒҜпјӣиҜ·еңЁдҪҝз”ЁжҲ‘д»¬дә§е“ҒпјҲжҲ–жңҚеҠЎпјүеүҚпјҢд»”з»Ҷйҳ…иҜ»е№¶дәҶи§Јжң¬гҖҠйҡҗз§Ғж”ҝзӯ–гҖӢгҖӮеҰӮжӮЁйҖүжӢ©дҪҝз”ЁжҲ–з»§з»ӯдҪҝз”ЁжҲ‘д»¬зҡ„жңҚеҠЎпјҢеҚіж„Ҹе‘ізқҖжӮЁе®Ңе…ЁзҗҶи§Јжң¬йҡҗз§Ғж”ҝзӯ–зҡ„е…ЁйғЁеҶ…е®№пјҢе№¶еҗҢж„ҸжҲ‘д»¬жҢүз…§жң¬йҡҗз§Ғж”ҝзӯ–ж”¶йӣҶгҖҒдҪҝз”ЁгҖҒеӮЁеӯҳе’ҢеҲҶйЎ№жӮЁзҡ„зӣёе…ідҝЎжҒҜгҖӮ</p><p><strong>е®ҡд№ү</strong></p><p>дёӘдәәдҝЎжҒҜпјҡд»Ҙз”өеӯҗжҲ–иҖ…е…¶е®ғж–№ејҸи®°еҪ•зҡ„иғҪеӨҹеҚ•зӢ¬жҲ–иҖ…дёҺе…¶е®ғдҝЎжҒҜз»“еҗҲиҜҶеҲ«зү№е®ҡиҮӘз„¶дәәиә«д»ҪжҲ–иҖ…еҸҚжҳ зү№е®ҡиҮӘз„¶дәәжҙ»еҠЁжғ…еҶөзҡ„еҗ„з§ҚдҝЎжҒҜпјҢеҢ…жӢ¬дҪҶдёҚйҷҗдәҺдёӘдәәе§“еҗҚгҖҒдҪҸеқҖгҖҒз”өиҜқеҸ·з ҒгҖҒиә«д»ҪиҜҒеҸ·з ҒзӯүгҖӮ</p><p>иҗҘй”ҖдҝЎжҒҜпјҡеҗ‘йЎҫе®ўйҖҡиҝҮеҢ…жӢ¬дҪҶдёҚйҷҗдәҺз”өеӯҗйӮ®д»¶гҖҒеҚіж—¶йҖҡи®ҜгҖҒзӨҫдәӨе№іеҸ°зӯүжё йҒ“еҸ‘йҖҒзҡ„з”ЁдәҺжҺЁе№ҝгҖҒжҺЁй”Җе•Ҷе“ҒжҲ–жңҚеҠЎзҡ„дҝЎжҒҜпјҢеҰӮжҙ»еҠЁгҖҒжңҚеҠЎжҲ–дә§е“ҒжҺЁе№ҝзӯүдҝЎжҒҜпјҢдҪҶдёҚеҢ…жӢ¬дёәдәҶеҗ‘йЎҫе®ўжҸҗдҫӣжңҚеҠЎиҖҢеҝ…йЎ»еҸ‘йҖҒзҡ„дҝЎжҒҜпјҢеҰӮзү©жөҒдҝЎжҒҜгҖҒжңҚеҠЎжҸҗзӨәзӯүгҖӮ</p><p><strong>жҲ‘д»¬еҰӮдҪ•ж”¶йӣҶе’ҢдҪҝз”ЁжӮЁзҡ„дёӘдәәдҝЎжҒҜпјҹ</strong></p><p>жҲ‘д»¬д»…дјҡеҮәдәҺжң¬ж”ҝзӯ–дёӯиҜҙжҳҺзҡ„д»ҘдёӢзӣ®зҡ„пјҢж”¶йӣҶе’ҢдҪҝз”ЁжӮЁзҡ„дёӘдәәдҝЎжҒҜгҖӮ</p><p><strong>жіЁеҶҢжҷҹжҪ®C-WAVEдјҡе‘ҳ</strong></p><p>дёәдәҶжіЁеҶҢжҷҹжҪ®C-WAVEдјҡе‘ҳпјҢжӮЁйңҖиҰҒжҸҗдҫӣжӮЁзҡ„жүӢжңәеҸ·з ҒгҖҒе§“еҗҚгҖҒжҖ§еҲ«еҸҠжӮЁзҡ„е№ҙйҫ„ж®өпјҢе№¶дёҺжӮЁзҡ„еҫ®дҝЎиҙҰеҸ·жҲ–ж”Ҝд»ҳе®қиҙҰеҸ·иҝӣиЎҢе…іиҒ”пјҢд»ҘдҫҝжҲ‘д»¬еҗ‘жӮЁжҸҗдҫӣеҜ№еә”зҡ„жңҚеҠЎгҖӮеҗҢж—¶пјҢеңЁжӮЁзҡ„жіЁеҶҢиҝҮзЁӢдёӯжҲ–жіЁеҶҢд№ӢеҗҺпјҢжӮЁеҸҜд»ҘйҖүжӢ©йўқеӨ–жҸҗдҫӣжӮЁзҡ„е©ҡе§»зҠ¶еҶөгҖҒе®¶еәӯзҠ¶еҶөгҖҒеӯҗеҘізҠ¶еҶөгҖҒе…ҙи¶ЈзҲұеҘҪгҖҒе·ҘдҪңиҒҢдҪҚгҖҒе…¬еҸёеҸҠж•ҷиӮІиғҢжҷҜгҖҒеҮәз”ҹе№ҙжңҲж—ҘгҖҒеұ…дҪҸең°гҖҒжӮЁжң¬дәәзҡ„зңҹе®һеӨҙеғҸзӯүпјҢд»ҘдҫҝжҲ‘д»¬дёәжӮЁжҸҗдҫӣдёӘжҖ§еҢ–зҡ„жңҚеҠЎеҸҠиҗҘй”ҖдҝЎжҒҜгҖӮ</p><p><strong>дјҡе‘ҳз§ҜеҲҶеҸҠжқғзӣҠ</strong></p><p>дёәе®ҢжҲҗдјҡе‘ҳз§ҜеҲҶжңҚеҠЎпјҢжӮЁеңЁжҷҹжҪ®C-WAVEе•ҶжҲ·ж¶Ҳиҙ№з»“иҙҰеҗҺпјҢе®ҢжҲҗз§ҜеҲҶеҠЁдҪңпјҢе°ҶжӮЁзҡ„дјҡе‘ҳдҝЎжҒҜдёҺжӮЁзҡ„ж¶Ҳиҙ№и®°еҪ•иҝӣиЎҢе…іиҒ”гҖӮ</p><p>жҲ‘д»¬дјҡж №жҚ®жӮЁзҡ„ж¶Ҳиҙ№и®°еҪ•жҲ–е…¶е®ғеҸҜиҺ·еҸ–гҖҒдҪҝз”Ёз§ҜеҲҶзҡ„иЎҢдёәпјҢжҸҗеҸ–жӮЁзҡ„ж¶Ҳиҙ№дҝЎжҒҜпјҢд»ҘдҫҝдёәжӮЁжҸҗдҫӣз§ҜеҲҶеҘ–еҠұе…‘жҚўгҖҒеҒңиҪҰдјҳжғ гҖҒжҙ»еҠЁеҸӮдёҺзӯүжңҚеҠЎгҖӮ</p><p>&nbsp;</p><p><strong>жҙ»еҠЁзҷ»и®°</strong></p><p>дёәдәҶжіЁеҶҢеҸӮеҠ жҷҹжҪ®C-WAVEжҸҗдҫӣзҡ„еҗ„зұ»жҙ»еҠЁпјҢжӮЁеңЁжіЁеҶҢзҷ»и®°ж—¶йңҖиҰҒжҸҗдҫӣжӮЁзҡ„иҒ”зі»ж–№ејҸпјҢеңЁжіЁеҶҢж—¶пјҢжӮЁеҸҜд»ҘйҖүжӢ©жҳҜеҗҰжҺҘеҸ—еҗҺз»ӯе…¶е®ғжҙ»еҠЁзҡ„йҖҡзҹҘгҖӮ</p><p><strong>еҒңиҪҰжңҚеҠЎ</strong></p><p>еңЁжҷҹжҪ®C-WAVEзҡ„еҫ®дҝЎе…¬дј—еҸ·дёӯпјҢжӮЁеҸҜд»Ҙе°ҶжӮЁзҡ„иҪҰзүҢеҸ·дёҺжӮЁзҡ„жҷҹжҪ®C-WAVEдјҡе‘ҳдҝЎжҒҜз»‘е®ҡпјҢд»ҘдҫҝжҲ‘д»¬дёәжӮЁжҸҗдҫӣеҝ«йҖҹж”Ҝд»ҳеҒңиҪҰиҙ№еҸҠеҒңиҪҰиҙ№еҮҸе…Қзү№жқғзӯүжңҚеҠЎгҖӮ</p><p><strong>ејҖеұ•еҶ…йғЁе®Ўи®ЎгҖҒж•°жҚ®еҲҶжһҗе’Ңз ”з©¶пјҢж”№е–„жҲ‘д»¬зҡ„дә§е“ҒжҲ–жңҚеҠЎ</strong></p><p>еңЁжҹҗдәӣжғ…еҶөдёӢпјҢжҲ‘д»¬еҸҜиғҪдјҡйңҖиҰҒжӮЁжҸҗдҫӣжӮЁдёӘдәәзҡ„зңҹе®һе§“еҗҚгҖҒиҒ”зі»ж–№ејҸгҖҒиҒ”зі»ең°еқҖе’Ңз”өеӯҗйӮ®з®ұпјҢжӮЁеңЁжҷҹжҪ®C-WAVEеҶ…дәӨжҳ“зҡ„и®°еҪ•пјҢжӮЁдҪҝз”ЁжҷҹжҪ®C-WAVEеңЁзәҝдјҡе‘ҳжңҚеҠЎи®ҫеӨҮгҖҒжүҖз»‘е®ҡеҫ®дҝЎиҙҰеҸ·зҡ„е”ҜдёҖиҜҶеҲ«з¬Ұе’ҢеңЁи®ҝй—®дёӯжүҖдҪҝз”Ёзҡ„ IP ең°еқҖпјӣд»ҘеҸҠжӮЁеҶіе®ҡдёҺжҲ‘д»¬еҲҶдә«зҡ„д»»дҪ•е…¶е®ғдҝЎжҒҜпјҢдҪҝжҲ‘д»¬иғҪеӨҹејҖеұ•еҶ…йғЁе®Ўи®ЎгҖҒж•°жҚ®еҲҶжһҗе’Ңз ”з©¶гҖӮиҝҷе°Ҷдјҡеё®еҠ©жҲ‘д»¬ж”№е–„жҷҹжҪ®C-WAVEзҡ„дә§е“Ғе’ҢжңҚеҠЎпјҢд»ҘдҫҝдёәжӮЁжҸҗдҫӣжӣҙеҠ з¬ҰеҗҲйңҖжұӮзҡ„дә§е“Ғе’ҢжңҚеҠЎгҖӮ</p><p><strong>жӮЁе……еҲҶзҹҘжҷ“пјҢд»ҘдёӢжғ…еҪўдёӯпјҢжҲ‘д»¬ж”¶йӣҶгҖҒдҪҝз”ЁдёӘдәәдҝЎжҒҜж— йңҖеҫҒеҫ—жӮЁзҡ„жҺҲжқғеҗҢж„Ҹпјҡ</strong></p><p>1гҖҒдёҺеӣҪе®¶е®үе…ЁгҖҒеӣҪйҳІе®үе…Ёжңүе…ізҡ„пјӣ</p><p>2гҖҒдёҺе…¬е…ұе®үе…ЁгҖҒе…¬е…ұеҚ«з”ҹгҖҒйҮҚеӨ§е…¬е…ұеҲ©зӣҠжңүе…ізҡ„пјӣ</p><p>3гҖҒдёҺзҠҜзҪӘдҫҰжҹҘгҖҒиө·иҜүгҖҒе®ЎеҲӨе’ҢеҲӨеҶіжү§иЎҢзӯүжңүе…ізҡ„пјӣ</p><p>4гҖҒеҮәдәҺз»ҙжҠӨдёӘдәәдҝЎжҒҜдё»дҪ“жҲ–е…¶д»–дёӘдәәзҡ„з”ҹе‘ҪгҖҒиҙўдә§зӯүйҮҚеӨ§еҗҲжі•жқғзӣҠдҪҶеҸҲеҫҲйҡҫеҫ—еҲ°жң¬дәәеҗҢж„Ҹзҡ„пјӣ</p><p>5гҖҒжүҖж”¶йӣҶзҡ„дёӘдәәдҝЎжҒҜжҳҜдёӘдәәдҝЎжҒҜдё»дҪ“иҮӘиЎҢеҗ‘зӨҫдјҡе…¬дј—е…¬ејҖзҡ„пјӣ</p><p>6гҖҒд»ҺеҗҲжі•е…¬ејҖжҠ«йңІзҡ„дҝЎжҒҜдёӯж”¶йӣҶзҡ„жӮЁзҡ„дёӘдәәдҝЎжҒҜпјҢеҰӮеҗҲжі•зҡ„ж–°й—»жҠҘйҒ“гҖҒж”ҝеәңдҝЎжҒҜе…¬ејҖзӯүжё йҒ“пјӣ</p><p>7гҖҒж №жҚ®жӮЁзҡ„иҰҒжұӮзӯҫи®ўе’ҢеұҘиЎҢеҗҲеҗҢжүҖеҝ…йңҖзҡ„пјӣ</p><p>8гҖҒз”ЁдәҺз»ҙжҠӨжүҖжҸҗдҫӣзҡ„дә§е“ҒжҲ–жңҚеҠЎзҡ„е®үе…ЁзЁіе®ҡиҝҗиЎҢжүҖеҝ…йңҖзҡ„пјҢдҫӢеҰӮеҸ‘зҺ°гҖҒеӨ„зҪ®дә§е“ҒжҲ–жңҚеҠЎзҡ„ж•…йҡңпјӣ</p><p>9гҖҒж”ҝеәңжҲ–зӣёе…іиҒҢиғҪйғЁй—ЁиҰҒжұӮжҸҗдҫӣзҡ„пјӣ</p><p>10гҖҒжі•еҫӢжі•и§„и§„е®ҡзҡ„е…¶е®ғжғ…еҪўгҖӮ</p><p><strong>жҲ‘д»¬д»Һз¬¬дёүж–№иҺ·еҫ—жӮЁдёӘдәәдҝЎжҒҜзҡ„жғ…еҪўпјҡ</strong></p><p>жҲ‘д»¬еҸҜиғҪд»Һз¬¬дёүж–№иҺ·еҸ–жӮЁжҺҲжқғе…ұдә«зҡ„иҙҰжҲ·дҝЎжҒҜпјҲеӨҙеғҸгҖҒжҳөз§°пјүпјҢе№¶еңЁжӮЁеҗҢж„Ҹжң¬йҡҗз§Ғж”ҝзӯ–еҗҺе°ҶжӮЁзҡ„з¬¬дёүж–№иҙҰжҲ·дёҺжӮЁеңЁжҷҹжҪ®C-WAVEзҡ„дјҡе‘ҳиҙҰжҲ·з»‘е®ҡпјҢдҪҝжӮЁеҸҜд»ҘйҖҡиҝҮз¬¬дёүж–№иҙҰжҲ·зӣҙжҺҘзҷ»еҪ•е№¶дҪҝз”ЁжҲ‘д»¬зҡ„дә§е“ҒжҲ–жңҚеҠЎгҖӮжҲ‘д»¬дјҡдҫқжҚ®дёҺз¬¬дёүж–№зҡ„зәҰе®ҡгҖҒеҜ№дёӘдәәдҝЎжҒҜжқҘжәҗзҡ„еҗҲжі•жҖ§иҝӣиЎҢзЎ®и®ӨеҗҺпјҢеңЁз¬ҰеҗҲзӣёе…іжі•еҫӢе’Ңжі•и§„и§„е®ҡзҡ„еүҚжҸҗдёӢпјҢдҪҝз”ЁжӮЁзҡ„иҝҷдәӣдёӘдәәдҝЎжҒҜгҖӮ</p><p>&nbsp;</p><p><strong>дҪҝз”ЁжӮЁдёӘдәәдҝЎжҒҜзҡ„и§„еҲҷпјҡ</strong></p><p>еҰӮжһңеҪ“жҲ‘д»¬иҰҒе°ҶдҝЎжҒҜз”ЁдәҺжң¬дјҡе‘ҳж”ҝзӯ–жңӘиҪҪжҳҺзҡ„е…¶е®ғз”ЁйҖ”ж—¶пјҢдјҡдәӢе…ҲеҫҒжұӮжӮЁзҡ„еҗҢж„ҸгҖӮ</p><p>еҪ“жҲ‘д»¬иҰҒе°Ҷз»ҷдәҲзү№е®ҡзӣ®зҡ„ж”¶йӣҶиҖҢжқҘзҡ„дҝЎжҒҜз”ЁдәҺе…¶е®ғзӣ®зҡ„ж—¶пјҢдјҡдәӢе…ҲеҫҒжұӮжӮЁзҡ„еҗҢж„ҸгҖӮ</p><p><strong>жӮЁзҡ„дёӘдәәдҝЎжҒҜжҳҜеҗҰдјҡиў«е…ұдә«гҖҒиҪ¬и®©жҲ–жҠ«йңІпјҡ</strong></p><p><strong>вҲҡе…ұдә«</strong></p><p>з”ұдәҺжҷҹжҪ®C-WAVEжүҖеұһзҡ„е•Ҷдёҡе…¬еҸёжҳҜдёҖе®¶е…ЁеӣҪжҖ§е…¬еҸёпјҢеҹәдәҺе•Ҷдёҡе…¬еҸёиҝҗиҗҘе’Ңз®ЎзҗҶзҡ„йңҖиҰҒпјҢжӮЁзҡ„дёӘдәәдҝЎжҒҜеҸҜиғҪдјҡеңЁе•Ҷдёҡе…¬еҸёеҶ…иў«е…ұдә«пјҢд»ҘдҫҝжҲ‘д»¬дёәжӮЁжҸҗдҫӣжӣҙдёәдјҳиҙЁзҡ„жңҚеҠЎгҖӮ</p><p>жҲ‘д»¬жүҝиҜәпјҢжүҖжңүзҡ„е…ұдә«д»…йҷҗжӮЁзҡ„еҝ…иҰҒдёӘдәәдҝЎжҒҜпјҢдё”еҸ—жң¬йҡҗз§Ғж”ҝзӯ–зҡ„зәҰжқҹпјӣеҰӮжһңжҲ‘д»¬иҰҒж”№еҸҳдёӘдәәдҝЎжҒҜзҡ„дҪҝз”ЁеҸҠеӨ„зҗҶзӣ®зҡ„пјҢжҲ‘д»¬е°ҶеҶҚж¬ЎеҫҒжұӮжӮЁзҡ„жҺҲжқғеҗҢж„ҸгҖӮеҗҢж—¶пјҢжҲ‘д»¬дјҡдёҘж јйҒөе®Ҳзӣёе…іжі•еҫӢжі•и§„еҜ№ж•°жҚ®дј иҫ“зҡ„еҗ„йЎ№иҰҒжұӮгҖӮ</p><p>жҲ‘д»¬дёҚдјҡдёҺе•Ҷдёҡе…¬еҸёд»ҘеӨ–зҡ„д»»дҪ•е…¬еҸёгҖҒз»„з»Үе’ҢдёӘдәәеҲҶдә«жӮЁзҡ„дёӘдәәдҝЎжҒҜпјҢдҪҶд»ҘдёӢжғ…еҶөйҷӨеӨ–пјҡ</p><p>1гҖҒеңЁиҺ·еҸ–жҳҺзЎ®еҗҢж„Ҹзҡ„жғ…еҶөдёӢе…ұдә«пјҡиҺ·еҫ—жӮЁзҡ„жҳҺзЎ®еҗҢж„ҸеҗҺпјҢжҲ‘д»¬дјҡдёҺе…¶д»–ж–№е…ұдә«жӮЁзҡ„дёӘдәәдҝЎжҒҜгҖӮ</p><p>2гҖҒжҲ‘д»¬еҸҜиғҪдјҡж №жҚ®жі•еҫӢжі•и§„и§„е®ҡпјҢжҲ–жҢүж”ҝеәңдё»з®ЎйғЁй—Ёзҡ„ејәеҲ¶жҖ§иҰҒжұӮпјҢеҜ№еӨ–е…ұдә«жӮЁзҡ„дёӘдәәдҝЎжҒҜгҖӮ</p><p>3гҖҒдёҺжҺҲжқғеҗҲдҪңдјҷдјҙе…ұдә«пјҡд»…дёәе®һзҺ°жң¬ж”ҝзӯ–дёӯеЈ°жҳҺзҡ„зӣ®зҡ„пјҢжҲ‘д»¬зҡ„жҹҗдәӣжңҚеҠЎе°Ҷз”ұжҺҲжқғеҗҲдҪңдјҷдјҙжҸҗдҫӣгҖӮжҲ‘д»¬еҸҜиғҪдјҡдёҺеҗҲдҪңдјҷдјҙе…ұдә«жӮЁзҡ„жҹҗдәӣдёӘдәәдҝЎжҒҜпјҢд»ҘжҸҗдҫӣжӣҙеҘҪзҡ„е®ўжҲ·жңҚеҠЎе’Ңз”ЁжҲ·дҪ“йӘҢгҖӮдҫӢеҰӮпјҢеңЁжӮЁзәҝдёҠиҙӯд№°жҲ‘д»¬зҡ„е•Ҷе“Ғж—¶пјҢжҲ‘д»¬еҝ…йЎ»дёҺзү©жөҒжңҚеҠЎжҸҗдҫӣе•Ҷе…ұдә«жӮЁзҡ„дёӘдәәдҝЎжҒҜжүҚиғҪе®үжҺ’йҖҒиҙ§пјҢжҲ–иҖ…е®үжҺ’еҗҲдҪңдјҷдјҙжҸҗдҫӣжңҚеҠЎгҖӮжҲ‘д»¬д»…дјҡеҮәдәҺеҗҲжі•гҖҒжӯЈеҪ“гҖҒеҝ…иҰҒгҖҒзү№е®ҡгҖҒжҳҺзЎ®зҡ„зӣ®зҡ„е…ұдә«жӮЁзҡ„дёӘдәәдҝЎжҒҜпјҢе№¶дё”еҸӘдјҡе…ұдә«жҸҗдҫӣжңҚеҠЎжүҖеҝ…йЎ»зҡ„дёӘдәәдҝЎжҒҜгҖӮжҲ‘д»¬зҡ„еҗҲдҪңдјҷдјҙж— жқғе°Ҷе…ұдә«зҡ„дёӘдәәдҝЎжҒҜз”ЁдәҺд»»дҪ•е…¶е®ғз”ЁйҖ”гҖӮ</p><p>зӣ®еүҚпјҢжҲ‘д»¬зҡ„жҺҲжқғеҗҲдҪңдјҷдјҙеҢ…жӢ¬д»ҘдёӢдёӨеӨ§зұ»еһӢпјҡ</p><p>1пјүе№ҝе‘ҠгҖҒеҲҶжһҗжңҚеҠЎзұ»зҡ„жҺҲжқғеҗҲдҪңдјҷдјҙгҖӮйҷӨйқһеҫ—еҲ°жӮЁзҡ„и®ёеҸҜпјҢеҗҰеҲҷжҲ‘д»¬дёҚдјҡе°ҶжӮЁзҡ„дёӘдәәиә«д»ҪдҝЎжҒҜпјҲжҢҮеҸҜд»ҘиҜҶеҲ«жӮЁиә«д»Ҫзҡ„дҝЎжҒҜпјҢдҫӢеҰӮе§“еҗҚжҲ–з”өеӯҗйӮ®з®ұпјҢйҖҡиҝҮиҝҷдәӣдҝЎжҒҜеҸҜд»ҘиҒ”зі»еҲ°жӮЁжҲ–иҜҶеҲ«жӮЁзҡ„иә«д»ҪпјүдёҺжҸҗдҫӣе№ҝе‘ҠгҖҒеҲҶжһҗжңҚеҠЎзҡ„еҗҲдҪңдјҷдјҙеҲҶдә«гҖӮжҲ‘д»¬дјҡеҗ‘иҝҷдәӣеҗҲдҪңдјҷдјҙжҸҗдҫӣжңүе…іе…¶е№ҝе‘ҠиҰҶзӣ–йқўе’Ңжңүж•ҲжҖ§зҡ„дҝЎжҒҜпјҢиҖҢдёҚдјҡжҸҗдҫӣжӮЁзҡ„дёӘдәәиә«д»ҪдҝЎжҒҜпјҢжҲ–иҖ…жҲ‘д»¬е°ҶиҝҷдәӣдҝЎжҒҜиҝӣиЎҢжұҮжҖ»пјҢд»Ҙдҫҝе®ғдёҚдјҡиҜҶеҲ«жӮЁдёӘдәәгҖӮ</p><p>2пјүдҫӣеә”е•ҶгҖҒжңҚеҠЎжҸҗдҫӣе•Ҷе’Ңе…¶д»–еҗҲдҪңдјҷдјҙгҖӮжҲ‘д»¬е°ҶжӮЁзҡ„дёӘдәәдҝЎжҒҜеҸ‘йҖҒз»ҷеңЁе…ЁеӣҪиҢғеӣҙеҶ…ж”ҜжҢҒжҲ‘д»¬дёҡеҠЎзҡ„дҫӣеә”е•ҶгҖҒжңҚеҠЎжҸҗдҫӣе•Ҷе’Ңе…¶д»–еҗҲдҪңдјҷдјҙпјҢиҝҷдәӣж”ҜжҢҒеҢ…жӢ¬жҸҗдҫӣзү©жөҒгҖҒй…ҚйҖҒжҲ–жҠҖжңҜеҹәзЎҖи®ҫж–ҪжңҚеҠЎгҖҒеҲҶжһҗжҲ‘д»¬жңҚеҠЎзҡ„дҪҝз”Ёж–№ејҸпјҢиЎЎйҮҸе№ҝе‘Ҡе’ҢжңҚеҠЎзҡ„жңүж•ҲжҖ§гҖҒжҸҗдҫӣе®ўжҲ·жңҚеҠЎгҖҒж”Ҝд»ҳдҫҝеҲ©жҲ–иҝӣиЎҢеӯҰжңҜз ”з©¶е’Ңи°ғжҹҘзӯүгҖӮеҜ№жҲ‘д»¬дёҺд№Ӣе…ұдә«дёӘдәәдҝЎжҒҜзҡ„е…¬еҸёгҖҒз»„з»Үе’ҢдёӘдәәпјҢжҲ‘д»¬дјҡдёҺе…¶зӯҫзҪІдёҘж јзҡ„дҝқеҜҶеҚҸи®®пјҢиҰҒжұӮд»–д»¬жҢүз…§жҲ‘д»¬зҡ„иҜҙжҳҺгҖҒжң¬йҡҗз§Ғж”ҝзӯ–д»ҘеҸҠе…¶е®ғд»»дҪ•зӣёе…ізҡ„дҝқеҜҶе’Ңе®үе…ЁжҺӘж–ҪжқҘеӨ„зҗҶдёӘдәәдҝЎжҒҜгҖӮ</p><p><strong>вҲҡиҪ¬и®©</strong></p><p>жҲ‘д»¬дёҚдјҡе°ҶжӮЁзҡ„дёӘдәәдҝЎжҒҜиҪ¬и®©з»ҷд»»дҪ•е…¬еҸёгҖҒз»„з»Үе’ҢдёӘдәәпјҢдҪҶд»ҘдёӢжғ…еҶөйҷӨеӨ–пјҡ</p><p>1гҖҒеңЁиҺ·еҸ–жҳҺзЎ®еҗҢж„Ҹзҡ„жғ…еҶөдёӢиҪ¬и®©пјҡиҺ·еҫ—жӮЁзҡ„жҳҺзЎ®еҗҢж„ҸеҗҺпјҢжҲ‘д»¬дјҡеҗ‘е…¶е®ғж–№иҪ¬и®©жӮЁзҡ„дёӘдәәдҝЎжҒҜпјӣ</p><p>2гҖҒеңЁж¶үеҸҠеҗҲе№¶гҖҒж”¶иҙӯжҲ–з ҙдә§жё…з®—ж—¶пјҢеҰӮж¶үеҸҠеҲ°дёӘдәәдҝЎжҒҜиҪ¬и®©пјҢжҲ‘д»¬дјҡиҰҒжұӮж–°зҡ„жҢҒжңүжӮЁдёӘдәәдҝЎжҒҜзҡ„е…¬еҸёгҖҒз»„з»Үз»§з»ӯеҸ—жӯӨж”ҝзӯ–зҡ„зәҰжқҹпјҢеҗҰеҲҷжҲ‘д»¬е°ҶиҰҒжұӮиҜҘе…¬еҸёгҖҒз»„з»ҮйҮҚж–°еҗ‘жӮЁеҫҒжұӮжҺҲжқғеҗҢж„ҸгҖӮ</p><p><strong>вҲҡе…¬ејҖжҠ«йңІ</strong></p><p>жҲ‘д»¬д»…дјҡеңЁд»ҘдёӢжғ…еҶөдёӢпјҢе…¬ејҖжҠ«йңІжӮЁзҡ„дёӘдәәдҝЎжҒҜпјҡ</p><p>1гҖҒиҺ·еҫ—жӮЁжҳҺзЎ®еҗҢж„ҸеҗҺгҖӮ</p><p>2гҖҒеҹәдәҺжі•еҫӢзҡ„жҠ«йңІпјҡеңЁжі•еҫӢгҖҒжі•еҫӢзЁӢеәҸгҖҒиҜүи®јжҲ–ж”ҝеәңдё»з®ЎйғЁй—ЁејәеҲ¶иҰҒжұӮзҡ„жғ…еҶөдёӢпјҢжҲ‘д»¬еҸҜиғҪдјҡе…¬ејҖжҠ«йңІжӮЁзҡ„дёӘдәәдҝЎжҒҜгҖӮ</p><p>3гҖҒжҲ‘д»¬и®ӨдёәжҠ«йңІеҜ№жЈҖжөӢгҖҒйҳІжӯўжҲ–д»Ҙе…¶е®ғж–№ејҸи§ЈеҶіж¬әиҜҲгҖҒе®үе…ЁжҲ–жҠҖжңҜй—®йўҳжҳҜеҗҲзҗҶеҝ…иҰҒзҡ„гҖӮ</p><p>4гҖҒжҲ‘д»¬и®ӨдёәжҠ«йңІеҜ№жҢүжі•еҫӢиҰҒжұӮжҲ–е…Ғи®ёзҡ„ж–№ејҸдҝқжҠӨжҲ‘д»¬зҡ„з”ЁжҲ·жҲ–е…¬дј—зҡ„жқғеҲ©гҖҒиҙўдә§жҲ–е®үе…ЁжҳҜеҗҲзҗҶеҝ…иҰҒзҡ„гҖӮ</p><p><strong>жӮЁзҡ„дёӘдәәдҝЎжҒҜе°Ҷиў«еҰӮдҪ•дҝқжҠӨпјҡ</strong></p><p>жҲ‘д»¬е·ІдҪҝз”Ёз¬ҰеҗҲдёҡз•Ңж ҮеҮҶзҡ„е®үе…ЁйҳІжҠӨжҺӘж–ҪдҝқжҠӨжӮЁжҸҗдҫӣзҡ„дёӘдәәдҝЎжҒҜпјҢйҳІжӯўж•°жҚ®йҒӯеҲ°жңӘз»ҸжҺҲжқғзҡ„и®ҝй—®гҖҒе…¬ејҖжҠ«йңІгҖҒдҪҝз”ЁгҖҒдҝ®ж”№гҖҒжҚҹеқҸжҲ–дёўеӨұгҖӮжҲ‘д»¬дјҡйҮҮеҸ–дёҖеҲҮеҗҲзҗҶеҸҜиЎҢзҡ„жҺӘж–ҪпјҢдҝқжҠӨжӮЁзҡ„дёӘдәәдҝЎжҒҜгҖӮ</p><p>жҲ‘д»¬еҗҢж—¶иҰҒжұӮеҸҜиғҪжҺҘи§ҰеҲ°жӮЁдёӘдәәдҝЎжҒҜзҡ„жүҖжңүдәәе‘ҳеұҘиЎҢзӣёеә”зҡ„дҝқеҜҶд№үеҠЎгҖӮеҰӮжһңжңӘиғҪеұҘиЎҢиҝҷдәӣд№үеҠЎпјҢеҸҜиғҪдјҡиў«иҝҪз©¶жі•еҫӢиҙЈд»»жҲ–иў«з»ҲжӯўдёҺжҲ‘д»¬зҡ„еҗҲдҪңе…ізі»гҖӮ</p><p>жҲ‘д»¬д»…еңЁжң¬ж”ҝзӯ–жүҖиҝ°зӣ®зҡ„жүҖеҝ…йңҖзҡ„жңҹй—ҙе’Ңжі•еҫӢжі•и§„иҰҒжұӮзҡ„ж—¶йҷҗеҶ…дҝқз•ҷжӮЁзҡ„дёӘдәәдҝЎжҒҜгҖӮеҰӮжһңеҪ“жҲ‘д»¬иҰҒе°ҶдҝЎжҒҜз”ЁдәҺжң¬ж”ҝзӯ–жңӘиҪҪжҳҺзҡ„е…¶е®ғз”ЁйҖ”ж—¶пјҢдјҡдәӢе…ҲеҫҒжұӮжӮЁзҡ„еҗҢж„ҸгҖӮ</p><p>жҲ‘д»¬е°ҶеңЁжүҝиҜәзҡ„иҢғеӣҙе’Ңзӣ®зҡ„дёӢдҪҝз”ЁжӮЁзҡ„дёӘдәәдҝЎжҒҜпјҢдҝқиҜҒжӮЁзҡ„жҺҲжқғиҢғеӣҙдёҺжүҖе‘ҠзҹҘзҡ„еҶ…е®№дёҖиҮҙгҖӮ</p><p>дә’иҒ”зҪ‘е№¶йқһз»қеҜ№е®үе…Ёзҡ„зҺҜеўғпјҢиҖҢдё”з”өеӯҗйӮ®д»¶гҖҒеҚіж—¶йҖҡи®ҜгҖҒзӨҫдәӨиҪҜд»¶зӯүдёҺе…¶д»–з”ЁжҲ·зҡ„дәӨжөҒж–№ејҸж— жі•зЎ®е®ҡжҳҜеҗҰе®Ңе…ЁеҠ еҜҶпјҢжҲ‘д»¬е»әи®®жӮЁдҪҝз”ЁжӯӨзұ»е·Ҙе…·ж—¶иҜ·дҪҝз”ЁеӨҚжқӮеҜҶз ҒпјҢе№¶жіЁж„ҸдҝқжҠӨжӮЁзҡ„дёӘдәәдҝЎжҒҜе®үе…ЁгҖӮ</p><p>еҗҢж—¶пјҢжҲ‘д»¬е°Ҷе§Ӣз»ҲеңЁз®ЎзҗҶгҖҒжҠҖжңҜеӨ„зҗҶзӯүиҝҮзЁӢдёӯе°ҪеҠӣзЎ®дҝқдҝЎжҒҜе®үе…ЁпјҢйҳІжӯўеҸ‘з”ҹдёӘдәәдҝЎжҒҜйқһжі•жі„йңІпјҢжҲ–еңЁжңӘз»ҸжҺҲжқғжғ…еҶөдёӢиў«дҪҝз”ЁгҖҒжҠ«йңІгҖҒдҝ®ж”№е’ҢеҲ еҮҸгҖӮжҲ‘д»¬е°ҶиҮҙеҠӣдәҺеҜ№жӮЁдёӘдәәдҝЎжҒҜе®һж–Ҫжңүж•ҲгҖҒеҫ—еҠӣзҡ„дҝқжҠӨжҺӘж–ҪпјҢдҪҝе…¶е…ҚеҸ—еҗ„з§ҚеҸҜйҒҮи§ҒдәӢж•…зҡ„еҚұе®ігҖӮ</p><p>еңЁдёҚе№ёеҸ‘з”ҹдёӘдәәдҝЎжҒҜе®үе…ЁдәӢд»¶еҗҺпјҢжҲ‘д»¬е°ҶжҢүз…§жі•еҫӢжі•и§„зҡ„иҰҒжұӮпјҢеҸҠж—¶еҗ‘жӮЁе‘ҠзҹҘпјҡе®үе…ЁдәӢд»¶зҡ„еҹәжң¬жғ…еҶөе’ҢеҸҜиғҪзҡ„еҪұе“ҚгҖҒжҲ‘д»¬е·ІйҮҮеҸ–жҲ–е°ҶиҰҒйҮҮеҸ–зҡ„еӨ„зҪ®жҺӘж–ҪпјҢжӮЁеҸҜиҮӘдё»йҳІиҢғе’ҢйҷҚдҪҺйЈҺйҷ©зҡ„е»әи®®гҖҒеҜ№жӮЁзҡ„иЎҘж•‘жҺӘж–ҪзӯүгҖӮжҲ‘д»¬е°ҶеҸҠж—¶е°ҶдәӢд»¶зӣёе…іжғ…еҶөд»ҘйӮ®д»¶гҖҒдҝЎеҮҪгҖҒз”өиҜқгҖҒжҺЁйҖҒйҖҡзҹҘзӯүж–№ејҸе‘ҠзҹҘжӮЁпјҢйҡҫд»ҘйҖҗдёҖе‘ҠзҹҘдёӘдәәдҝЎжҒҜдё»дҪ“ж—¶пјҢжҲ‘д»¬дјҡйҮҮеҸ–еҗҲзҗҶгҖҒжңүж•Ҳзҡ„ж–№ејҸеҸ‘еёғе…¬е‘ҠгҖӮ</p><p>еҗҢж—¶пјҢжҲ‘д»¬иҝҳе°ҶжҢүз…§зӣ‘з®ЎйғЁй—ЁиҰҒжұӮпјҢдё»еҠЁдёҠжҠҘдёӘдәәдҝЎжҒҜе®үе…ЁдәӢд»¶зҡ„еӨ„зҪ®жғ…еҶөгҖӮ</p><p><strong>жӮЁзҡ„жқғеҲ©пјҡ</strong></p><p>жҲ‘д»¬е°ҶйҮҮеҸ–йҖӮеҪ“зҡ„жҠҖжңҜжүӢж®өпјҢдҝқиҜҒжӮЁи®ҝй—®гҖҒжӣҙж–°гҖҒжӣҙжӯЈжҲ–еҲ йҷӨжӮЁдёӘдәәдҝЎжҒҜзҡ„жқғеҲ©пјҢжҸҗдҫӣдёҺжӮЁдёӘдәәдҝЎжҒҜж”¶йӣҶгҖҒдҪҝз”ЁгҖҒеҲҶдә«гҖҒеӯҳеӮЁзӯүж–№йқўзӣёе…ізҡ„еӨҡз§ҚйҖүжӢ©гҖӮ</p><p><strong>вҲҡи®ҝй—®жқғдёҺжӣҙжӯЈжқғ</strong></p><p>жӮЁжңүжқғеҜ№й”ҷиҜҜжҲ–дёҚе®Ңж•ҙзҡ„дҝЎжҒҜдҪңеҮәжӣҙжӯЈжҲ–жӣҙж–°пјҢжӮЁеҸҜд»Ҙи®ҝй—® вҖңжҷҹжҪ®C-WAVEвҖқ еҫ®дҝЎе…¬дј—еҸ·пјҢиҝӣе…Ҙдјҡе‘ҳе°ҸзЁӢеәҸе№іеҸ° - дёӘдәәдёӯеҝғпјҢжӣҙж–°дјҡе‘ҳиө„ж–ҷе№¶иЎҘе……жіЁеҶҢж—¶жҸҗдҫӣзҡ„дҝЎжҒҜпјӣеҗҢж—¶пјҢжӮЁеҸҜд»ҘйҖҡиҝҮеҫ®дҝЎе…¬дј—еҸ·дёӯжҸҗдҫӣзҡ„е…¶е®ғиҸңеҚ•пјҢжҹҘзңӢжӮЁеңЁжҷҹжҪ®C-WAVEеҶ…з•ҷеӯҳзҡ„е…¶е®ғдҝЎжҒҜеҸҠи®°еҪ•гҖӮ</p><p>еҜ№дәҺжӮЁеңЁдҪҝз”ЁжҲ‘д»¬зҡ„дә§е“ҒжҲ–жңҚеҠЎиҝҮзЁӢдёӯдә§з”ҹзҡ„е…¶е®ғдёӘдәәдҝЎжҒҜйңҖиҰҒи®ҝй—®жҲ–жӣҙжӯЈпјҢиҜ·йҡҸж—¶иҒ”зі»жҲ‘д»¬гҖӮжҲ‘д»¬дјҡж №жҚ®жң¬йҡҗз§Ғж”ҝзӯ–жүҖеҲ—жҳҺзҡ„ж–№ејҸе’Ңжңҹйҷҗе“Қеә”жӮЁзҡ„иҜ·жұӮгҖӮдҪҶиҜ·жіЁж„ҸпјҢз”ұдәҺжҠҖжңҜйҷҗеҲ¶жҲ–е®үе…ЁжҖ§иҖғиҷ‘пјҢжӮЁзҡ„йғЁеҲҶдёӘдәәдҝЎжҒҜжҲ‘д»¬иҝҳж— жі•дёәжӮЁжҸҗдҫӣи®ҝй—®е’ҢжӣҙжӯЈзҡ„жңҚеҠЎгҖӮ</p><p><strong>вҲҡеҲ йҷӨжқғ</strong></p><p>еҰӮжһңжҲ‘д»¬иҝқеҸҚжі•еҫӢжі•и§„жҲ–дёҺжӮЁзҡ„зәҰе®ҡж”¶йӣҶгҖҒдҪҝз”ЁгҖҒдёҺд»–дәәеҲҶдә«жӮЁзҡ„дёӘдәәдҝЎжҒҜпјҢжӮЁжңүжқғиҰҒжұӮжҲ‘д»¬иҝӣиЎҢеҲ йҷӨгҖӮжӮЁеҸҜж №жҚ® вҖңиҒ”зі»жҲ‘д»¬вҖқ йғЁеҲҶжүҖеҲ—зҡ„ж–№ејҸдёҺжҲ‘д»¬иҒ”з»ңиҰҒжұӮиҝӣиЎҢдёӘдәәдҝЎжҒҜзҡ„еҲ йҷӨгҖӮ</p><p><strong>вҲҡж’Өй”Җжқғ</strong></p><p>жҲ‘д»¬зҡ„жҜҸдёӘдёҡеҠЎеҠҹиғҪйңҖиҰҒдёҖдәӣеҹәжң¬зҡ„дҝЎжҒҜжүҚиғҪеҫ—д»Ҙе®ҢжҲҗгҖӮжӮЁеҸҜд»ҘйҖҡиҝҮеҲ йҷӨдҝЎжҒҜгҖҒе…ій—ӯи®ҫеӨҮеҠҹиғҪпјҢеңЁ вҖңжҷҹжҪ®C-WAVEвҖқ еҫ®дҝЎе…¬дј—еҸ·дёӯжӣҙж–°йҡҗз§Ғи®ҫзҪ®зӯүж–№ејҸж”№еҸҳжӮЁжҺҲжқғжҲ‘д»¬з»§з»ӯж”¶йӣҶдёӘдәәдҝЎжҒҜзҡ„иҢғеӣҙжҲ–ж’ӨеӣһжӮЁзҡ„жҺҲжқғгҖӮжӮЁд№ҹеҸҜд»ҘйҖҡиҝҮжіЁй”ҖиҙҰжҲ·зҡ„ж–№ејҸпјҢж’ӨеӣһжҲ‘д»¬з»§з»ӯж”¶йӣҶжӮЁдёӘдәәзҡ„е…ЁйғЁжҺҲжқғгҖӮеҜ№дәҺжҲ‘д»¬йўқеӨ–ж”¶йӣҶзҡ„дёӘдәәдҝЎжҒҜпјҢеҜ№е…¶зҡ„ж”¶йӣҶе’ҢдҪҝз”ЁпјҢжӮЁеҸҜд»ҘйҡҸж—¶з»ҷдәҲжҲ–ж”¶еӣһжӮЁзҡ„жҺҲжқғеҗҢж„ҸгҖӮеҰӮжһңеңЁжӯӨиҝҮзЁӢдёӯпјҢжӮЁйңҖиҰҒд»»дҪ•её®еҠ©пјҢеҸҜдёҺжҲ‘д»¬иҒ”з»ңгҖӮ</p><p><strong>иҗҘй”ҖдҝЎжҒҜзҡ„йҖҖи®ўпјҡ</strong></p><p>жӮЁеҸҜд»ҘйҖүжӢ©жҳҜеҗҰжҺҘеҸ—жҲ‘д»¬гҖҒжҲ‘д»¬зҡ„е…іиҒ”дјҒдёҡжҲ–жңҚеҠЎжҸҗдҫӣе•ҶйҖҡиҝҮз”өеӯҗйӮ®д»¶гҖҒзҹӯдҝЎгҖҒеҚ°еҲ·жқҗж–ҷзӯүеҸ‘йҖҒиҗҘй”ҖдҝЎжҒҜгҖӮжӮЁеҸҜд»ҘеңЁ вҖңжҷҹжҪ®C-WAVEвҖқ еҫ®дҝЎе…¬дј—еҸ·жӣҙж–°жӮЁзҡ„иҗҘй”ҖдҝЎжҒҜи®ўйҳ…еҒҸеҘҪи®ҫзҪ®гҖӮеҜ№дәҺеҫ®дҝЎе…¬дј—еҸ·дёӯжҺЁйҖҒзҡ„иҗҘй”ҖдҝЎжҒҜпјҢжӮЁеҸҜд»ҘйҖҡиҝҮеҫ®дҝЎдёӯжҸҗдҫӣзҡ„е…¬дј—еҸ· вҖңжҺҘеҸ—ж–Үз« жҺЁйҖҒвҖқ и®ҫзҪ®ејҖе…іе…ій—ӯжҺЁйҖҒгҖӮ</p><p><strong>е“Қеә”жӮЁзҡ„дёҠиҝ°иҜ·жұӮпјҡ</strong></p><p>дёәдҝқйҡңе®үе…ЁпјҢжӮЁеҸҜиғҪйңҖиҰҒжҸҗдҫӣд№ҰйқўиҜ·жұӮпјҢжҲ–д»Ҙе…¶е®ғж–№ејҸиҜҒжҳҺжӮЁзҡ„иә«д»ҪгҖӮжҲ‘д»¬еҸҜиғҪдјҡе…ҲиҰҒжұӮжӮЁйӘҢиҜҒиҮӘе·ұзҡ„иә«д»ҪпјҢз„¶еҗҺеҶҚеӨ„зҗҶжӮЁзҡ„иҜ·жұӮгҖӮжҲ‘д»¬е°ҶеңЁ 30 дёӘе·ҘдҪңж—ҘеҶ…еҒҡеҮәзӯ”еӨҚгҖӮ</p><p>еҜ№дәҺжӮЁеҗҲзҗҶзҡ„иҜ·жұӮпјҢжҲ‘д»¬еҺҹеҲҷдёҠдёҚж”¶еҸ–иҙ№з”ЁпјҢдҪҶеҜ№еӨҡж¬ЎйҮҚеӨҚгҖҒи¶…еҮәеҗҲзҗҶйҷҗеәҰзҡ„иҜ·жұӮпјҢжҲ‘д»¬е°Ҷи§Ҷжғ…еҶөж”¶еҸ–дёҖе®ҡжҲҗжң¬иҙ№з”ЁгҖӮеҜ№дәҺйӮЈдәӣж— з«ҜйҮҚеӨҚгҖҒйңҖиҰҒиҝҮеӨҡжҠҖжңҜжүӢж®өпјҲдҫӢеҰӮпјҢйңҖиҰҒејҖеҸ‘ж–°зі»з»ҹжҲ–д»Һж №жң¬дёҠж”№еҸҳзҺ°иЎҢз®ЎзҗҶпјүгҖҒз»ҷд»–дәәеҗҲжі•жқғзӣҠеёҰжқҘйЈҺйҷ©жҲ–йқһеёёдёҚеҲҮе®һйҷ…зҡ„иҜ·жұӮпјҢжҲ‘д»¬дјҡдәҲд»ҘжӢ’з»қгҖӮ</p><p>еңЁд»ҘдёӢжғ…еҪўдёӯпјҢжҢүз…§жі•еҫӢжі•и§„иҰҒжұӮпјҢжҲ‘д»¬е°Ҷж— жі•е“Қеә”жӮЁзҡ„иҜ·жұӮпјҡ</p><p>1гҖҒдёҺеӣҪе®¶е®үе…ЁгҖҒеӣҪйҳІе®үе…ЁзӣҙжҺҘзӣёе…ізҡ„пјӣ</p><p>2гҖҒдёҺе…¬е…ұе®үе…ЁгҖҒе…¬е…ұеҚ«з”ҹгҖҒйҮҚеӨ§е…¬е…ұеҲ©зӣҠзӣҙжҺҘзӣёе…ізҡ„пјӣ</p><p>3гҖҒдёҺзҠҜзҪӘдҫҰжҹҘгҖҒиө·иҜүгҖҒе®ЎеҲӨе’ҢеҲӨеҶіжү§иЎҢзӯүзӣҙжҺҘзӣёе…ізҡ„пјӣ</p><p>4гҖҒжңүе……еҲҶиҜҒжҚ®иЎЁжҳҺжӮЁеӯҳеңЁдё»и§ӮжҒ¶ж„ҸжҲ–ж»Ҙз”ЁжқғеҲ©зҡ„пјӣ</p><p>5гҖҒе“Қеә”жӮЁзҡ„иҜ·жұӮе°ҶеҜјиҮҙжӮЁжҲ–е…¶д»–дёӘдәәгҖҒз»„з»Үзҡ„еҗҲжі•жқғзӣҠеҸ—еҲ°жҚҹе®ізҡ„пјӣ</p><p>6гҖҒж¶үеҸҠе•Ҷдёҡз§ҳеҜҶзҡ„гҖӮ</p><p><strong>жҲ‘д»¬еҰӮдҪ•еӨ„зҗҶжңӘжҲҗе№ҙдәәзҡ„дёӘдәәдҝЎжҒҜпјҡ</strong></p><p>жҷҹжҪ®C-WAVEдёҚдјҡдё»еҠЁеҗ‘жңӘж»Ў 18 е‘ЁеІҒзҡ„жңӘжҲҗе№ҙдәәеҜ»жұӮжҲ–ж”¶йӣҶдёӘдәәдҝЎжҒҜгҖӮиҜ·жӮЁеңЁдҪҝз”ЁжҲ‘д»¬зҡ„жңҚеҠЎеүҚпјҢзЎ®дҝқиҮӘе·ұжҳҜе…·жңүе®Ңе…Ёж°‘дәӢиЎҢдёәиғҪеҠӣзҡ„жҲҗе№ҙдәәпјҢжҲ–иҖ…еңЁе®¶й•ҝгҖҒзӣ‘жҠӨдәәжҢҮеҜјдёӢдҪҝз”ЁжҲ‘д»¬зҡ„жңҚеҠЎгҖӮе®¶й•ҝгҖҒзӣ‘жҠӨдәәеңЁеҗ‘жҲ‘д»¬жҸҗдҫӣжңӘжҲҗе№ҙдәәдҝЎжҒҜеүҚпјҢиҜ·д»”з»Ҷйҳ…иҜ»жҲ‘д»¬зҡ„йҡҗз§Ғж”ҝзӯ–пјҢд»ҘжӣҙеҘҪең°е‘өжҠӨжӮЁзҡ„еӯ©еӯҗгҖӮ</p><p>жҲ‘д»¬дёҚдјҡеҗ‘жңӘжҲҗе№ҙдәәеҸ‘йҖҒд»»дҪ•иҗҘй”ҖдҝЎжҒҜгҖӮеҰӮжһңжҲ‘д»¬еҸ‘зҺ°иҮӘе·ұеңЁжңӘдәӢе…ҲиҺ·еҫ—еҸҜиҜҒе®һзҡ„е®¶й•ҝгҖҒзӣ‘жҠӨдәәеҗҢж„Ҹзҡ„жғ…еҶөдёӢж”¶йӣҶдәҶжңӘжҲҗе№ҙдәәзҡ„дёӘдәәдҝЎжҒҜпјҢжҲ‘д»¬дјҡи®ҫжі•е°Ҫеҝ«еҲ йҷӨзӣёе…іж•°жҚ®гҖӮ</p><p><strong>жң¬ж”ҝзӯ–еҰӮдҪ•жӣҙж–°</strong></p><p>жҲ‘д»¬еҸҜиғҪдјҡдёҚе®ҡж—¶дҝ®ж”№жң¬ж”ҝзӯ–пјҢд»ҘдҫҝеҸҠж—¶еҸҚжҳ еӣҪе®¶жі•еҫӢжі•и§„зҡ„еҸҳеҢ–д»ҘеҸҠжҲ‘д»¬жңҚеҠЎж”ҝзӯ–зҡ„и°ғж•ҙгҖӮжӮЁз»§з»ӯдҪҝз”ЁжҲ‘д»¬зҡ„жңҚеҠЎе°Ҷи§ҶдёәжӮЁеҜ№жң¬йҡҗз§Ғж”ҝзӯ–зӣёе…іи°ғж•ҙзҡ„еҗҢж„ҸгҖӮ</p><p>жңӘз»ҸжӮЁжҳҺзЎ®еҗҢж„ҸпјҢжҲ‘д»¬дёҚдјҡеүҠеҮҸжӮЁжҢүз…§жң¬йҡҗз§Ғж”ҝзӯ–жүҖеә”дә«жңүзҡ„жқғеҲ©гҖӮеҜ№дәҺйҮҚеӨ§еҸҳжӣҙпјҢжҲ‘д»¬иҝҳдјҡжҸҗдҫӣжӣҙдёәжҳҫи‘—зҡ„йҖҡзҹҘгҖӮ</p><p>жң¬ж”ҝзӯ–жүҖжҢҮзҡ„йҮҚеӨ§еҸҳжӣҙеҢ…жӢ¬дҪҶдёҚйҷҗдәҺпјҡ</p><p>1гҖҒжҲ‘д»¬зҡ„жңҚеҠЎи§„жЁЎеҸ‘з”ҹйҮҚеӨ§еҸҳеҢ–гҖӮеҰӮеӨ„зҗҶдёӘдәәдҝЎжҒҜзҡ„зӣ®зҡ„гҖҒеӨ„зҗҶдёӘдәәдҝЎжҒҜзҡ„зұ»еһӢгҖҒдёӘдәәдҝЎжҒҜзҡ„дҪҝз”Ёж–№ејҸзӯүпјӣ</p><p>2гҖҒжҲ‘д»¬еңЁжүҖжңүжқғз»“жһ„гҖҒз»„з»Үжһ¶жһ„зӯүж–№йқўеҸ‘з”ҹйҮҚеӨ§еҸҳеҢ–гҖӮеҰӮдёҡеҠЎи°ғж•ҙгҖҒз ҙдә§е№¶иҙӯзӯүеј•иө·зҡ„жүҖжңүиҖ…еҸҳжӣҙзӯүпјӣ</p><p>3гҖҒдёӘдәәдҝЎжҒҜе…ұдә«гҖҒиҪ¬и®©жҲ–е…¬ејҖжҠ«йңІзҡ„дё»иҰҒеҜ№иұЎеҸ‘з”ҹеҸҳеҢ–пјӣ</p><p>4гҖҒжӮЁеҸӮдёҺдёӘдәәдҝЎжҒҜеӨ„зҗҶж–№йқўзҡ„жқғеҲ©еҸҠе…¶иЎҢдҪҝж–№ејҸеҸ‘з”ҹйҮҚеӨ§еҸҳеҢ–пјӣ</p><p>5гҖҒжҲ‘д»¬иҙҹиҙЈеӨ„зҗҶдёӘдәәдҝЎжҒҜе®үе…Ёзҡ„иҙЈд»»йғЁй—ЁгҖҒиҒ”з»ңж–№ејҸеҸҠжҠ•иҜүжё йҒ“еҸ‘з”ҹеҸҳеҢ–ж—¶пјӣ</p><p>6гҖҒдёӘдәәдҝЎжҒҜе®үе…ЁеҪұе“ҚиҜ„дј°жҠҘе‘ҠиЎЁжҳҺеӯҳеңЁй«ҳйЈҺйҷ©ж—¶гҖӮ</p><p><strong>д»»дҪ•з–‘й—®</strong></p><p>еҰӮжһңжӮЁеҜ№жң¬ж”ҝзӯ–жҲ–жҲ‘д»¬жүҖжӢҘжңүзҡ„дёҺжӮЁзӣёе…ізҡ„дёӘдәәдҝЎжҒҜжңүд»»дҪ•з–‘й—®жҲ–дёҚж»ЎпјҢиҜ·йҡҸж—¶иҒ”зі»жҲ‘д»¬гҖӮ</p><p>дёҖиҲ¬жғ…еҶөдёӢпјҢжҲ‘д»¬е°ҶеңЁ 30 дёӘе·ҘдҪңж—ҘеҶ…еӣһеӨҚгҖӮ</p><p>жӮЁеҗҢж„Ҹеӣ жң¬ж”ҝзӯ–еј•еҸ‘зҡ„д»»дҪ•жӮЁе’ҢжҲ‘д»¬д№Ӣй—ҙзҡ„зә зә·пјҲд»ҘдёӢз®Җз§° вҖңзә зә·вҖқпјүеқҮйҖӮз”ЁдёӯеҚҺдәәж°‘е…ұе’ҢеӣҪжі•еҫӢпјҢйҷӨеҶІзӘҒи§„еҲҷеӨ–гҖӮйҷӨйқһеҸҰжңүзҰҒжӯўпјҢжӮЁеҗҢж„Ҹз”ұжӯӨеј•еҸ‘зҡ„зӣҙжҺҘжҲ–й—ҙжҺҘдә§з”ҹзҡ„жҲ–дёҺд№Ӣзӣёе…ізҡ„зә зә·гҖҒзҙўиө”е’ҢиҜүи®јеқҮеә”жҸҗдәӨжң¬йЎ№зӣ®жүҖеңЁең°жңүз®Ўиҫ–жқғзҡ„жі•йҷўдҫқз…§дёӯеҚҺдәәж°‘е…ұе’ҢеӣҪжі•еҫӢи§ЈеҶігҖӮ</p>', '2025-11-05 16:30:12', '2025-11-05 16:30:12');
