INSERT INTO `em_shop_infos` VALUES (3, 3, NULL, 'https://oss.lanlnk.com/gs-scrm-dev/images/default/202510/29/JZOLnqIOxUm3XriVVZPmFMJoIwO8kgTCIQjbLvQN.png', 'https://oss.lanlnk.com/gs-scrm-dev/images/default/202511/05/Oh6IfLLRBpOBcfkoYcLiZeHtgxO2FIUvU6BpB3j5.png', '113622862728', '10:00-22:00', 'еҚҺдёәиҮҙеҠӣдәҺжҠҠж•°еӯ—дё–з•ҢеёҰе…ҘжҜҸдёӘдәәгҖҒжҜҸдёӘе®¶еәӯгҖҒжҜҸдёӘз»„з»ҮпјҢжһ„е»әдёҮзү©дә’иҒ”зҡ„жҷәиғҪдё–з•Ңпјҡи®©ж— еӨ„дёҚеңЁзҡ„иҒ”жҺҘпјҢжҲҗдёәдәәдәәе№ізӯүзҡ„жқғеҲ©пјҢжҲҗдёәжҷәиғҪдё–з•Ңзҡ„еүҚжҸҗе’ҢеҹәзЎҖпјӣдёәдё–з•ҢжҸҗдҫӣеӨҡж ·жҖ§з®—еҠӣпјҢи®©дә‘ж— еӨ„дёҚеңЁпјҢи®©жҷәиғҪж— жүҖдёҚеҸҠпјӣжүҖжңүзҡ„иЎҢдёҡе’Ңз»„з»ҮпјҢеӣ ејәеӨ§зҡ„ж•°еӯ—е№іеҸ°иҖҢеҸҳеҫ—ж•ҸжҚ·гҖҒй«ҳж•ҲгҖҒз”ҹжңәеӢғеӢғпјӣйҖҡиҝҮAIйҮҚж–°е®ҡд№үдҪ“йӘҢпјҢи®©ж¶Ҳиҙ№иҖ…еңЁе®¶еұ…гҖҒеҮәиЎҢгҖҒеҠһе…¬гҖҒеҪұйҹіеЁұд№җгҖҒиҝҗеҠЁеҒҘеә·зӯүе…ЁеңәжҷҜиҺ·еҫ—жһҒиҮҙзҡ„дёӘжҖ§еҢ–жҷәж…§дҪ“йӘҢгҖӮ', NULL, 'е№ҝе·һз•ӘзҰә', 'еҚҺдёәиҮҙеҠӣдәҺжҠҠж•°еӯ—дё–з•ҢеёҰе…ҘжҜҸдёӘдәәгҖҒжҜҸдёӘе®¶еәӯгҖҒжҜҸдёӘз»„з»ҮпјҢжһ„е»әдёҮзү©дә’иҒ”зҡ„жҷәиғҪдё–з•Ңпјҡи®©ж— еӨ„дёҚеңЁзҡ„иҒ”жҺҘпјҢжҲҗдёәдәәдәәе№ізӯүзҡ„жқғеҲ©пјҢжҲҗдёәжҷәиғҪдё–з•Ңзҡ„еүҚжҸҗе’ҢеҹәзЎҖпјӣдёәдё–з•ҢжҸҗдҫӣеӨҡж ·жҖ§з®—еҠӣпјҢи®©дә‘ж— еӨ„дёҚеңЁпјҢи®©жҷәиғҪж— жүҖдёҚеҸҠпјӣжүҖжңүзҡ„иЎҢдёҡе’Ңз»„з»ҮпјҢеӣ ејәеӨ§зҡ„ж•°еӯ—е№іеҸ°иҖҢеҸҳеҫ—ж•ҸжҚ·гҖҒй«ҳж•ҲгҖҒз”ҹжңәеӢғеӢғпјӣйҖҡиҝҮAIйҮҚж–°е®ҡд№үдҪ“йӘҢпјҢи®©ж¶Ҳиҙ№иҖ…еңЁе®¶еұ…гҖҒеҮәиЎҢгҖҒеҠһе…¬гҖҒеҪұйҹіеЁұд№җгҖҒиҝҗеҠЁеҒҘеә·зӯүе…ЁеңәжҷҜиҺ·еҫ—жһҒиҮҙзҡ„дёӘжҖ§еҢ–жҷәж…§дҪ“йӘҢгҖӮ', '2025-10-29 17:01:55', '2025-11-05 15:53:40', NULL, NULL, NULL, NULL, NULL, '2021', NULL, 0, 0, 0, NULL, NULL, 900, 1600);
